package com.example.secondphone.security;
import java.io.IOException;import org.springframework.http.MediaType;import org.springframework.security.access.AccessDeniedException;import org.springframework.security.web.access.AccessDeniedHandler;import org.springframework.stereotype.Component;import com.fasterxml.jackson.databind.ObjectMapper;import com.example.secondphone.exception.ApiErrorResponse;import jakarta.servlet.http.*;
@Component public class RestAccessDeniedHandler implements AccessDeniedHandler{private final ObjectMapper mapper;public RestAccessDeniedHandler(ObjectMapper mapper){this.mapper=mapper;}@Override public void handle(HttpServletRequest request,HttpServletResponse response,AccessDeniedException exception)throws IOException{response.setStatus(403);response.setContentType(MediaType.APPLICATION_JSON_VALUE);mapper.writeValue(response.getOutputStream(),ApiErrorResponse.of("權限不足",request.getRequestURI()));}}
